let url = '';
let clipSeconds = 20;
try {
  const wh = $('Webhook 수신').all();
  if (wh.length) {
    const raw = wh[0].json;
    const b = raw.body ?? raw;
    const parsed = typeof b === 'string' ? JSON.parse(b) : b;
    if (parsed?.url) url = String(parsed.url).trim();
    if (parsed?.clipSeconds != null) clipSeconds = Math.max(5, Math.min(25, Number(parsed.clipSeconds) || 20));
  }
} catch {}
// 테스트(수동 실행)용 기본 URL
if (!url) url = 'https://www.youtube.com/shorts/cnVzHVTfhXE';

const executionId = ($execution && $execution.id) ? String($execution.id) : String(Date.now());
const clipPath = `/tmp/bgm-clip-${executionId}`;

return [{ json: { url, clipSeconds, clipPath, source: 'n8n' } }];

const params = $('파라미터 파싱').first().json;
const audd = $input.first().json;

let track = null;
let message = '';

if (!audd || typeof audd !== 'object') {
  message = 'AudD 응답을 받지 못했습니다. AUDD_API_TOKEN 환경변수와 네트워크 상태를 확인하세요.';
} else if (audd.status === 'error') {
  const code = audd?.error?.error_code;
  const errMsg = audd?.error?.error_message || 'AudD API 오류';
  message = code === 901 || code === 900
    ? `AudD 인증 실패: ${errMsg} — n8n 컨테이너의 AUDD_API_TOKEN 값을 확인하세요.`
    : `AudD 인식 실패: ${errMsg}`;
} else {
  const r = audd.result;
  if (r && r.title) {
    track = {
      title: String(r.title),
      artist: r.artist ? String(r.artist) : undefined,
      album: r.album ? String(r.album) : undefined,
      releaseDate: r.release_date ? String(r.release_date) : undefined,
      label: r.label ? String(r.label) : undefined,
      links: {
        spotify: r.spotify?.external_urls?.spotify || undefined,
        appleMusic: r.apple_music?.url || undefined,
      },
      source: 'audd',
    };
    message = `'${track.title}'${track.artist ? ` - ${track.artist}` : ''} 식별 완료 (AudD 음향 지문 매칭 — 추정이 아닌 실제 매칭 결과)`;
  } else {
    message = 'AudD DB에서 일치하는 곡을 찾지 못했습니다 (미등록 곡이거나 클립 구간에 BGM이 약하게 섞여 있을 수 있음).';
  }
}

return [{ json: {
  ok: true,
  mode: 'n8n-audd',
  url: params.url,
  track,
  message,
} }];

let url = '';
try { url = $('파라미터 파싱').first().json.url || ''; } catch {}

return [{ json: {
  ok: false,
  mode: 'fallback',
  url,
  track: null,
  message: 'BGM 정밀 식별 실패 — 오디오 클립 추출(yt-dlp/ffmpeg) 또는 AudD 호출 중 오류가 발생했습니다. n8n 컨테이너에 yt-dlp·ffmpeg가 설치되어 있는지, AUDD_API_TOKEN이 설정되어 있는지 확인하세요.',
} }];
